  6	
  7	const getLabels = () => ({
  8	  'option-1': ['value-1', 'value-2'],
  9	  'option-2': ['value-3', 'value-4'],
 10	});
 11	
 12	describe('Label expression selector', () => {
 13	  test('Verify expression selection', async () => {
 14	    const user = userEvent.setup();
 15	    let selectedExpression: MatchExpression[] = [];
 16	    const onChange = jest.fn((expression: MatchExpression[]) => {
 17	      selectedExpression = expression;
 18	    });
 19	
 20	    const component = () => (
 21	      <LabelExpressionSelector
 22	        labels={getLabels()}
 23	        addExpressionString={'Add resource'}
 24	        onChange={onChange}
 25	        isValidationEnabled={false}
 26	        selectedExpressions={selectedExpression}
 27	      />
 28	    );
 29	
 30	    const { rerender } = render(component());
 31	
 32	    // Verify add resource
 33	    await userEvent.click(screen.getByText('Add resource'));
 34	
 35	    // Rerender after argument change
 36	    rerender(component());
 37	
 38	    // Verify expand section before selection
 39	    expect(screen.getByText('Expand to enter expression')).toBeInTheDocument();
 40	
 41	    // Verify header text
 42	    expect(screen.getByText('Label')).toBeInTheDocument();
 43	    expect(screen.getByText('Operator')).toBeInTheDocument();
 44	    expect(screen.getByText('Values')).toBeInTheDocument();
 45	
 46	    // Step 1: Select label
 47	    const labelInput =
 48	      screen.queryByPlaceholderText(/select a label/i) ||
 49	      screen.queryByRole('textbox', { name: /type to filter/i });
 50	
 51	    if (!labelInput) {
 52	      throw new Error('Could not find the "Select a label" input field');
 53	    }
 54	
 55	    await user.click(labelInput);
 56	
 57	    // Wait for dropdown options to appear
 58	    const option1 = await screen.findByText('option-1');
 59	    const option2 = await screen.findByText('option-2');
 60	
 61	    expect(option1).toBeInTheDocument();
 62	    expect(option2).toBeInTheDocument();
 63	
 64	    await user.click(option1);
 65	
 66	    rerender(component());
 67	    expect(screen.getByText('option-1')).toBeInTheDocument();
 68	
 69	    // Step 2: Select operator
 70	    // PFv5 renders operator as typeahead input
 71	    const operatorInput =
 72	      screen.queryByPlaceholderText(/select options/i) ||
 73	      screen.queryByRole('textbox', { name: /type to filter/i });
 74	
 75	    if (!operatorInput) {
 76	      throw new Error('Could not find the "Operator" input field');
 77	    }
 78	
 79	    // Click to open dropdown
 80	    await user.click(operatorInput);
 81	
 82	    // Wait for operator options to appear
 83	    const notInOption = await screen.findByText((c) => c.trim() === 'NotIn');
 84	    const existsOption = await screen.findByText((c) => c.trim() === 'Exists');
 85	    const doesNotExistOption = await screen.findByText(
 86	      (c) => c.trim() === 'DoesNotExist'
 87	    );
 88	
 89	    expect(notInOption).toBeInTheDocument();
 90	    expect(existsOption).toBeInTheDocument();
 91	    expect(doesNotExistOption).toBeInTheDocument();
 92	
 93	    await user.click(notInOption);
 94	
 95	    rerender(component());
 96	    expect(screen.getByText('NotIn')).toBeInTheDocument();
 97	
 98	    // Step 3: Select values
 99	    // Find the Values section and its combobox input
100	    const valuesSection = screen
101	      .getByText('Values')
102	      .closest('.pf-v6-c-form__group');
103	    const valueInput = valuesSection?.querySelector('[role="combobox"]');
104	
105	    if (!valueInput) {
106	      throw new Error('Could not find the values input field');
107	    }
108	
109	    await user.click(valueInput);
110	
111	    const value1 = await screen.findByText('value-1');
112	    const value2 = await screen.findByText('value-2');
113	
114	    await user.click(value1);
115	    rerender(component());
116	    await user.click(value2);
117	    rerender(component());
118	
119	    //Step 4: Verify final expanded text
120	    expect(
121	      screen.getByText('option-1 does not equal any of value-1, value-2')
122	    ).toBeInTheDocument();
123	  });
124	
125	  test('Verify error validation', async () => {
126	    const selectedExpression: MatchExpression[] = [
127	      {
128	        key: '',
129	        operator: 'In',
130	        values: [],
131	      },
132	    ];
133	    const onChange = jest.fn();
134	
135	    render(
136	      <LabelExpressionSelector
137	        labels={getLabels()}
138	        addExpressionString={'Add resource'}
139	        onChange={onChange}
140	        isValidationEnabled={true}
141	        selectedExpressions={selectedExpression}
142	      />
143	    );
144	
145	    // Verify validation error message
146	    const errors = screen.getAllByText('Required');
147	    expect(errors).toHaveLength(2);
148	    expect(
149	      screen.getByText('Expand to fix validation errors')
150	    ).toBeInTheDocument();
151	  });
152	});

