  1	import * as React from 'react';
  2	import { RedExclamationCircleIcon } from '@odf/shared/status/icons';
  3	import { MatchExpression } from '@openshift-console/dynamic-plugin-sdk';
  4	import { SVGIconProps } from '@patternfly/react-icons/dist/esm/createIcon';
  5	import * as _ from 'lodash-es';
  6	import { TFunction } from 'react-i18next';
  7	import {
  8	  FormFieldGroupExpandable,
  9	  Button,
 10	  ButtonVariant,
 11	  Divider,
 12	  Form,
 13	  Grid,
 14	  FormGroup,
 15	  GridItem,
 16	  Split,
 17	  SplitItem,
 18	  FormFieldGroupHeader,
 19	  HelperText,
 20	  HelperTextItem,
 21	  FormHelperText,
 22	  SelectOption,
 23	} from '@patternfly/react-core';
 24	import { TrashIcon, PlusCircleIcon } from '@patternfly/react-icons';
 25	import { SingleSelectDropdown, MultiSelectDropdown } from '../dropdown';
 26	import { useCustomTranslation } from '../useCustomTranslationHook';
 27	import { getValidatedProp } from '../utils';
 28	import { AsyncLoader } from '../utils/AsyncLoader';
 29	import './labelExpressionSelector.scss';
 30	
 31	/**
 32	 * Set up an AsyncComponent to wrap the label-expression-selector to allow on demand loading to reduce the
 33	 * vendor footprint size.
 34	 */
 35	export const LazyLabelExpressionSelector = (
 36	  props: LabelExpressionSelectorProps
 37	) => (
 38	  <AsyncLoader
 39	    loader={() =>
 40	      import('../label-expression-selector').then(
 41	        (c) => c.LabelExpressionSelector
 42	      )
 43	    }
 44	    {...props}
 45	  />
 46	);
 47	
 48	export const isLabelOnlyOperator = (operator: string) =>
 49	  [Operator.Exists, Operator.DoesNotExist].includes(operator as Operator);
 50	
 51	const matchExpressionSummaryError = (
 52	  expandString: string,
 53	  t: TFunction
 54	): React.ReactNode => (
 55	  <Split>
 56	    <SplitItem>
 57	      <RedExclamationCircleIcon />
 58	    </SplitItem>
 59	    <SplitItem>
 60	      <span className="pf-v6-c-form__helper-text pf-m-error">
 61	        &nbsp; {expandString || t('Expand to fix validation errors')}
 62	      </span>
 63	    </SplitItem>
 64	  </Split>
 65	);
 66	
 67	export const matchExpressionSummary = (
 68	  t: TFunction,
 69	  expression: MatchExpression,
 70	  expandString?: string,
 71	  isValidationEnabled?: boolean
 72	) => {
 73	  const { key, operator, values } = expression;
 74	
 75	  // Skipping values check for label only operator.
 76	  const hasError =
 77	    !key || (isLabelOnlyOperator(operator) ? false : !values.length);
 78	
 79	  // Converting the selected label expression as text to summerize,
 80	  // Only for the display purpose
 81	  let operatorStr = t('unknown');
 82	  switch (operator) {
 83	    case Operator.In:
 84	      if (!!values && values.length > 1) {
 85	        operatorStr = t('equals any of');
 86	      } else {
 87	        operatorStr = t('equals');
 88	      }
 89	      break;
 90	    case Operator.NotIn:
 91	      if (!!values && values.length > 1) {
 92	        operatorStr = t('does not equal any of');
 93	      } else {
 94	        operatorStr = t('does not equal');
 95	      }
 96	      break;
 97	    case Operator.Exists:
 98	      operatorStr = t('exists');
 99	      break;
100	    case Operator.DoesNotExist:
101	      operatorStr = t('does not exist');
102	      break;
103	  }
104	  // For empty, default message will be displayed,
105	  // For non-mepty, summerized expression text will be displayed
106	  if (isValidationEnabled && hasError) {
107	    return matchExpressionSummaryError(expandString, t);
108	  } else {
109	    return !key
110	      ? expandString || t('Expand to enter expression')
111	      : `${key} ${operatorStr} ${values.join(', ')}`;
112	  }
113	};
114	
115	const ExpressionElement: React.FC<ExpressionElementProps> = ({
116	  index,
117	  selectedExpression,
118	  labels,
119	  isValidationEnabled,
120	  onSelect,
121	}) => {
122	  const { key, operator, values } = selectedExpression;
123	
124	  const { t } = useCustomTranslation();
125	
126	  // Display each label key as options
127	  const keyOptions = React.useMemo(
128	    () =>
129	      Object.keys(labels).map((labelKey) => (
130	        <SelectOption key={labelKey} value={labelKey}>
131	          {labelKey}
132	        </SelectOption>
133	      )),
134	    [labels]
135	  );
136	
137	  // Default options of Operator enum.
138	  const operatorOptions = Object.values(Operator).map((option) => (
139	    <SelectOption key={option} value={option}>
140	      {option}
141	    </SelectOption>
142	  ));
143	
144	  // Display each values of the selected key as options
145	  // Modify value options based on key selection.
146	  const valueOptions = React.useMemo(
147	    () =>
148	      (!!key ? labels[key] || [] : []).map((value) => (
149	        <SelectOption key={value} value={value}>
150	          {value}{' '}
151	        </SelectOption>
152	      )),
153	    [labels, key]
154	  );
155	
156	  // Reset values when label is selected.
157	  const onKeyChange = React.useCallback(
158	    (selectedKey: string) => {
159	      onSelect(index, {
160	        key: selectedKey,
161	        operator,
162	        values: key === selectedKey ? values : [],
163	      });
164	    },
165	    [index, key, operator, values, onSelect]
166	  );
167	
168	  // Reset values when label only operator is selected.
169	  const onOperatorChange = React.useCallback(
170	    (selectedOperator: Operator) => {
171	      onSelect(index, {
172	        ...selectedExpression,
173	        operator: selectedOperator,
174	        values: !isLabelOnlyOperator(selectedOperator) ? values : [],
175	      });
176	    },
177	    [index, selectedExpression, values, onSelect]
178	  );
179	
180	  // Call onSelect to update the state
181	  const onValuesChange = React.useCallback(
182	    (selectedValues: string[]) => {
183	      onSelect(index, {
184	        ...selectedExpression,
185	        values: selectedValues,
186	      });
187	    },
188	    [index, selectedExpression, onSelect]
189	  );
190	
191	  const isKeyValid = getValidatedProp(isValidationEnabled && !key);
192	  const isValuesValid = getValidatedProp(isValidationEnabled && !values.length);
193	
194	  return (
195	    <Grid hasGutter>
196	      <GridItem lg={4} sm={4}>
197	        <FormGroup label={t('Label')} hasNoPaddingTop isRequired>
198	          <SingleSelectDropdown
199	            data-test={`key-selection-dropdown-${index}`}
200	            id="label-selection-dropdown"
201	            placeholderText={t('Select a label')}
202	            selectedKey={key}
203	            selectOptions={keyOptions}
204	            onChange={onKeyChange}
205	            hasInlineFilter
206	            required
207	            validated={isKeyValid}
208	            isCreatable
209	          />
210	          <FormHelperText>
211	            <HelperText>
212	              <HelperTextItem variant={isKeyValid}>
213	                {isKeyValid === 'error' && t('Required')}
214	              </HelperTextItem>
215	            </HelperText>
216	          </FormHelperText>
217	        </FormGroup>
218	      </GridItem>
219	      <GridItem lg={4} sm={4}>
220	        <FormGroup label={t('Operator')} hasNoPaddingTop>
221	          <SingleSelectDropdown
222	            data-test={`operator-selection-dropdown-${index}`}
223	            id="operator-selection-dropdown"
224	            selectedKey={operator}
225	            selectOptions={operatorOptions}
226	            onChange={onOperatorChange}
227	            hasInlineFilter
228	            required
229	          />
230	        </FormGroup>
231	      </GridItem>
232	      {!isLabelOnlyOperator(operator) && (
233	        <GridItem lg={4} sm={4}>
234	          <FormGroup label={t('Values')} hasNoPaddingTop isRequired>
235	            <MultiSelectDropdown
236	              data-test={`values-selection-dropdown-${index}`}
237	              id="values-selection-dropdown"
238	              placeholderText={
239	                !!values?.length
240	                  ? t('{{count}} selected', { count: values.length })
241	                  : t('Select the values')
242	              }
243	              selections={values}
244	              variant={'checkbox'}
245	              selectOptions={valueOptions}
246	              onChange={onValuesChange}
247	              hasInlineFilter
248	              validated={isValuesValid}
249	              isCreatable
250	            />
251	            <FormHelperText>
252	              <HelperText>
253	                <HelperTextItem variant={isValuesValid}>
254	                  {isValuesValid === 'error' && t('Required')}
255	                </HelperTextItem>
256	              </HelperText>
257	            </FormHelperText>
258	          </FormGroup>
259	        </GridItem>
260	      )}
261	    </Grid>
262	  );
263	};
264	
265	const ArrayInput: React.FC<ArrayInputProps> = ({
266	  index,
267	  selectedExpression,
268	  labels,
269	  expandString,
270	  isValidationEnabled,
271	  DeleteIcon,
272	  onSelect,
273	}) => {
274	  const { t } = useCustomTranslation();
275	
276	  const expandSectionName = `expand-section-${index}`;
277	
278	  return (
279	    <>
280	      <Divider />
281	      <Form>
282	        {/* Expand section */}
283	        <FormFieldGroupExpandable
284	          className="odf-label-expression-selector__expandBody--padding-top"
285	          key={expandSectionName}
286	          data-test={expandSectionName}
287	          toggleAriaLabel={expandSectionName}
288	          isExpanded
289	          header={
290	            // Expand section header
291	            <FormFieldGroupHeader
292	              titleText={{
293	                id: index.toString(),
294	                text: matchExpressionSummary(
295	                  t,
296	                  selectedExpression,
297	                  expandString,
298	                  isValidationEnabled
299	                ),
300	              }}
301	              actions={
302	                <Button
303	                  data-test={`delete-expression-${index}`}
